// Component test with Playwright CT — isolated, real browser
import { test, expect } from '@playwright/experimental-ct-react';
import { DatePicker } from './DatePicker';

test('closes on Escape and returns focus to trigger', async ({ mount }) => {
  const component = await mount(<DatePicker label="Due date" />);

  await component.getByRole('button', { name: 'Due date' }).click();
  await expect(component.getByRole('dialog')).toBeVisible();

  await component.press('Escape');
  await expect(component.getByRole('dialog')).toBeHidden();
  await expect(component.getByRole('button', { name: 'Due date' })).toBeFocused();
});

import { test, expect } from '@playwright/test';

test('user submits contact form', async ({ page }) => {
  await page.goto('/contact');

  // Query by label — survives HTML restructuring
  await page.getByLabel('Email address').fill('dev@example.com');
  await page.getByLabel('Message').fill('Hello from Playwright');

  // Query by role + accessible name — not by class or selector
  await page.getByRole('button', { name: 'Send message' }).click();

  // Assert observable outcome, not DOM mutation
  await expect(page.getByRole('alert')).toHaveText('Message sent!');
});

import { test, expect } from '@playwright/experimental-ct-react';
import { StatusBadge } from './StatusBadge';

test('shows error styling when status is failed', async ({ mount }) => {
  const component = await mount(<StatusBadge status="failed" label="Build" />);

  await expect(component).toHaveText('Build');
  await expect(component).toHaveAttribute('data-status', 'failed');
  await expect(component.getByRole('img', { name: /error/i })).toBeVisible();

  await component.update({ props: { status: 'success', label: 'Build' } });
  await expect(component).toHaveAttribute('data-status', 'success');
});

