import { test, expect } from '@playwright/test';

test('debounced search updates after 500ms', async ({ page }) => {
  await page.clock.install();
  await page.goto('/search');

  await page.getByRole('searchbox').fill('playwright');

  // Debounce hasn't fired yet — results still empty
  await expect(page.getByTestId('results')).toBeEmpty();

  // Advance clock past debounce threshold
  await page.clock.fastForward(500);

  await expect(page.getByTestId('results')).not.toBeEmpty();

  // Assert specific network call was made
  await page.waitForResponse(resp =>
    resp.url().includes('/api/search') && resp.status() === 200
  );
});

