import { test, expect } from '@playwright/test';

test('mocks API and captures trace on retry', async ({ page }) => {
  await page.route('**/api/feed', async route => {
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ items: [{ id: 1, title: 'Mocked Byte' }] }),
    });
  });

  await page.goto('/feed');
  await expect(page.getByText('Mocked Byte')).toBeVisible();

  // Simulate upstream error for error-boundary test
  await page.route('**/api/feed', route => route.fulfill({ status: 500 }));
  await page.reload();
  await expect(page.getByRole('alert')).toBeVisible();
});

import { test, expect } from '@playwright/test';

test.beforeEach(async ({ page }) => {
  await page.route('**/api/posts', (route) =>
    route.fulfill({ status: 200, json: [{ id: 1, title: 'Hello' }] })
  );
});

test('shows error state on 500', async ({ page }) => {
  // Most-recent handler wins — overrides the beforeEach stub
  await page.route('**/api/posts', (route) =>
    route.fulfill({ status: 500, json: { error: 'Server error' } })
  );

  await page.goto('/feed');
  await expect(page.getByRole('alert')).toContainText('Failed to load posts');
});

